     1	import { useModelIndex, useModelTrashed } from '@rhino-dev/rhino-react';
     2	import { Link } from 'react-router-dom';
     3	import type { Project, Task, Label, User } from '../types';
     4	import { Icon } from '../components/Icons';
     5	import { fmtRelative } from '../lib/format';
     6	
     7	export function DashboardPage() {
     8	  const projects  = useModelIndex<Project>('projects',                 { perPage: 100 });
     9	  const tasks     = useModelIndex<Task & { assignee?: User }>('tasks', { perPage: 100, includes: ['assignee'] });
    10	  const labels    = useModelIndex<Label>('labels',                     { perPage: 100 });
    11	  const trashProj = useModelTrashed<Project>('projects');
    12	
    13	  const projectList = projects.data?.data ?? [];
    14	  const taskList    = tasks.data?.data    ?? [];
    15	  const labelList   = labels.data?.data   ?? [];
    16	  const trashCount  = trashProj.data?.data?.length ?? 0;
    17	
    18	  const activeProjects = projectList.filter(p => p.status === 'active').length;
    19	  const inProgressTasks = taskList.filter(t => t.status === 'in_progress').length;
    20	  const overdueTasks    = taskList.filter(t => t.due_date && new Date(t.due_date) < new Date() && t.status !== 'done').length;
    21	
    22	  return (
    23	    <>
    24	      <div className="page-head">
    25	        <div>
    26	          <h1 className="page-title">Dashboard</h1>
    27	          <p className="page-sub">Overview of your workspace activity</p>
    28	        </div>
    29	      </div>
    30	
    31	      <div className="stats">
    32	        <Stat label="Active projects" value={activeProjects} hint={`${projectList.length} total`} />
    33	        <Stat label="In progress"     value={inProgressTasks} hint={`${taskList.length} tasks total`} />
    34	        <Stat label="Overdue"         value={overdueTasks} hint="past due date" />
    35	        <Stat label="Labels"          value={labelList.length} hint="across resources" />
    36	        <Stat label="In trash"        value={trashCount} hint="restorable" />
    37	      </div>
    38	
    39	      <div className="detail-grid">
    40	        <div className="card">
    41	          <div className="card-header">
    42	            <div className="card-title">Recent projects</div>
    43	            <Link className="btn btn-ghost btn-sm" to="/projects">View all <Icon.arrowR size={12} /></Link>
    44	          </div>
    45	          {projects.isLoading ? <Loading /> : (
    46	            <table className="table">
    47	              <thead><tr><th>Project</th><th>Status</th><th>Updated</th></tr></thead>
    48	              <tbody>
    49	                {projectList.slice(0, 5).map(p => (
    50	                  <tr key={p.id}>
    51	                    <td>
    52	                      <Link to={`/projects/${p.id}`} style={{ fontWeight: 600 }}>{p.title}</Link>
    53	                      <div className="faint" style={{ fontSize: 12 }}>{p.description?.slice(0, 80)}</div>
    54	                    </td>
    55	                    <td><StatusPill value={p.status} /></td>
    56	                    <td className="faint">{fmtRelative(p.updated_at)}</td>
    57	                  </tr>
    58	                ))}
    59	                {projectList.length === 0 && <tr><td colSpan={3} className="card-empty">No projects yet.</td></tr>}
    60	              </tbody>
    61	            </table>
    62	          )}
    63	        </div>
    64	
    65	        <div className="card">
    66	          <div className="card-header">
    67	            <div className="card-title">Hot tasks</div>
    68	            <Link className="btn btn-ghost btn-sm" to="/tasks">View all <Icon.arrowR size={12} /></Link>
    69	          </div>
    70	          <div style={{ padding: 14, display: 'flex', flexDirection: 'column', gap: 10 }}>
    71	            {tasks.isLoading ? <Loading /> :
    72	              taskList.filter(t => t.priority === 'critical' || t.priority === 'high').slice(0, 6).map(t => (
    73	                <div key={t.id} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
    74	                  <PriorityPill value={t.priority} />
    75	                  <div style={{ flex: 1 }}>
    76	                    <div style={{ fontWeight: 500 }}>{t.title}</div>
    77	                    <div className="faint" style={{ fontSize: 11 }}>
    78	                      {t.assignee?.name ?? 'unassigned'} · due {fmtRelative(t.due_date)}
    79	                    </div>
    80	                  </div>
    81	                  <StatusPill value={t.status} />
    82	                </div>
    83	              ))}
    84	            {taskList.length === 0 && <div className="card-empty">No tasks.</div>}
    85	          </div>
    86	        </div>
    87	      </div>
    88	    </>
    89	  );
    90	}
    91	
    92	function Stat({ label, value, hint }: { label: string; value: number; hint?: string }) {
    93	  return (
    94	    <div className="stat">
    95	      <div className="stat-label">{label}</div>
    96	      <div className="stat-value">{value}</div>
    97	      {hint && <div className="stat-hint">{hint}</div>}
    98	    </div>
    99	  );
   100	}
   101	
   102	export function StatusPill({ value }: { value: string }) {
   103	  return <span className={`pill pill-${value}`}><span className="pill-dot" />{value.replace('_', ' ')}</span>;
   104	}
   105	
   106	export function PriorityPill({ value }: { value: string }) {
   107	  return <span className={`pill pill-${value}`}>{value}</span>;
   108	}
   109	
   110	export function Loading() {
   111	  return <div className="loading"><span className="spinner" /> Loading…</div>;
   112	}
